const items = $input.all(); // all input items
const now = new Date();
now.setHours(0,0,0,0); // ignore time-of-day

const output = [];

for (const item of items) {
  const dateStr = item.json.Date_Echeance;

  if (!dateStr) {
    console.log(`Skipping row_number ${item.json.row_number || "unknown"}: Date_Echeance is missing`);
    continue;
  }

  const parts = dateStr.split("/").map(Number);
  if (parts.length !== 3 || parts.some(isNaN)) {
    console.log(`Skipping row_number ${item.json.row_number || "unknown"}: Invalid Date_Echeance format: "${dateStr}"`);
    continue;
  }

  const [day, month, year] = parts;
  const dateEcheance = new Date(year, month - 1, day);
  const threeDaysBefore = new Date(dateEcheance);
  threeDaysBefore.setDate(dateEcheance.getDate() - 3);

  if (now >= threeDaysBefore && now <= dateEcheance) {
    item.json.myNewField = 1; // example new field

    // Calculate remaining days
    const diffTime = dateEcheance - now; // difference in milliseconds
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    item.json.jours_restants = diffDays;

    output.push(item);
  } else {
    console.log(`Skipping row_number ${item.json.row_number || "unknown"}: Not within 3-day range`);
  }
}

return output;

